INSERT INTO `courses` (`slug`,`title`,`short_description`,`description`,`level`,`duration_hours`,`thumbnail`,`banner`,`requirements`,`objectives`,`category`,`tags`,`status`,`total_lessons`) VALUES
('inteligencia-artificial','Inteligencia Artificial: De Cero a Experto','Domina los fundamentos de la IA, desde logica computacional hasta redes neuronales.','Este curso te llevara desde los conceptos basicos de la logica computacional hasta la implementacion de redes neuronales capaces de aprender por si solas. Aprenderas los principios matematicos detras del Machine Learning, como funcionan los algoritmos de clasificacion y como entrenar modelos con datos reales. Al final del curso seras capaz de construir tu propio perceptron y entender la arquitectura de una red neuronal profunda.','Intermedio',40,'assets/images/courses/ia-thumb.jpg','assets/images/courses/ia-banner.jpg','Conocimientos basicos de matematicas y logica.|Python basico (recomendado).','Comprender que es la IA y sus aplicaciones reales.|Implementar un Perceptron desde cero.|Entrenar redes neuronales simples.|Aplicar algoritmos de clasificacion.|Evaluar modelos de ML.','Inteligencia Artificial','IA, Machine Learning, Redes Neuronales, Python','active',12),
