-- ============================================================
-- SEED SCRIPT - Datos de ejemplo para plataforma profesional
-- Limpia datos viejos e inserta 8 cursos completos con modulos y lecciones
-- ============================================================
SET NAMES utf8mb4;
SET FOREIGN_KEY_CHECKS = 0;

-- Limpiar datos de prueba anteriores
DELETE FROM lesson_progress;
DELETE FROM lessons;
DELETE FROM modules;
DELETE FROM enrollments;
DELETE FROM certificates;
DELETE FROM reviews;
DELETE FROM notifications;
DELETE FROM courses;
ALTER TABLE courses AUTO_INCREMENT = 1;
ALTER TABLE modules AUTO_INCREMENT = 1;
ALTER TABLE lessons AUTO_INCREMENT = 1;

-- ============================================================
-- CURSOS PROFESIONALES
-- ============================================================

('machine-learning','Machine Learning Practico con Python','Aprende los algoritmos esenciales de ML y aplicalos en proyectos reales.','Sumergete en el mundo del Machine Learning con un enfoque completamente practico. Aprenderas regresion, clasificacion, clustering y mucho mas, usando Python y las librerias mas demandadas por la industria como scikit-learn, pandas y matplotlib. Cada modulo incluye un proyecto real que podras agregar a tu portafolio profesional.','Avanzado',50,'assets/images/courses/ml-thumb.jpg','assets/images/courses/ml-banner.jpg','Python intermedio.|Estadistica basica.|Algebra lineal basica.','Implementar algoritmos supervisados y no supervisados.|Preprocesar datos correctamente.|Evaluar y optimizar modelos.|Desplegar modelos en produccion.|Construir un portafolio de proyectos ML.','Inteligencia Artificial','ML, Python, scikit-learn, Data Science','active',12),

('python-desde-cero','Python desde Cero: La Guia Completa','Aprende a programar en Python desde absoluto cero hasta nivel intermedio-avanzado.','Python es el lenguaje de programacion mas demandado del mundo. En este curso aprenderas todo lo que necesitas saber para convertirte en un programador Python competente. Cubrimos desde la instalacion del entorno, variables y estructuras de datos, hasta programacion orientada a objetos, manejo de archivos, APIs y mucho mas. Perfecto para principiantes sin experiencia previa en programacion.','Basico',35,'assets/images/courses/python-thumb.jpg','assets/images/courses/python-banner.jpg','No se requiere experiencia previa en programacion.','Instalar y configurar Python correctamente.|Manejar variables, listas, diccionarios y funciones.|Programar orientado a objetos en Python.|Leer y escribir archivos.|Consumir APIs REST.|Crear scripts de automatizacion.','Programacion','Python, Programacion, Backend, Scripting','active',15),

('sql-bases-de-datos','SQL y Bases de Datos Relacionales','Domina SQL desde lo basico hasta consultas avanzadas y diseno de bases de datos.','Las bases de datos son el corazon de cualquier aplicacion moderna. En este curso aprenderas SQL desde cero: como crear tablas, insertar datos, hacer consultas complejas con JOINs, subconsultas, indices y procedimientos almacenados. Tambien aprenderas a disenar esquemas de bases de datos eficientes usando normalizacion y buenas practicas de la industria.','Basico',25,'assets/images/courses/sql-thumb.jpg','assets/images/courses/sql-banner.jpg','No se requiere experiencia previa.|Logica basica de computacion.','Crear y gestionar bases de datos MySQL/PostgreSQL.|Escribir consultas SELECT, INSERT, UPDATE, DELETE.|Usar JOINs para combinar tablas.|Disenar esquemas normalizados.|Optimizar consultas con indices.|Usar transacciones y procedimientos almacenados.','Bases de Datos','SQL, MySQL, PostgreSQL, Bases de Datos','active',10),

('desarrollo-web-full-stack','Desarrollo Web Full Stack Moderno','Construye aplicaciones web completas con HTML, CSS, JavaScript, PHP y MySQL.','El desarrollo web Full Stack te permite crear aplicaciones completas de principio a fin. En este curso aprenderas todo el stack tecnologico moderno: desde estructurar paginas con HTML5 y estilizarlas con CSS3, hasta crear interactividad con JavaScript, construir APIs con PHP y persistir datos con MySQL. Terminaras el curso con dos proyectos reales completos en tu portafolio.','Intermedio',60,'assets/images/courses/web-thumb.jpg','assets/images/courses/web-banner.jpg','Conocimientos basicos de computacion.|Python o cualquier lenguaje de programacion (recomendado).','Crear estructuras HTML5 semanticas.|Disenar interfaces responsivas con CSS3.|Programar interactividad con JavaScript ES6+.|Construir APIs RESTful con PHP.|Gestionar bases de datos MySQL.|Desplegar aplicaciones en servidor.','Desarrollo Web','HTML, CSS, JavaScript, PHP, MySQL, Full Stack','active',15),

('algoritmos-geneticos','Algoritmos Geneticos y Computacion Evolutiva','Aprende a resolver problemas complejos de optimizacion con algoritmos inspirados en la biologia.','La computacion evolutiva es una de las areas mas fascinantes de la inteligencia artificial. Los algoritmos geneticos imitan el proceso de seleccion natural para encontrar soluciones optimas a problemas que serian imposibles de resolver con metodos tradicionales. En este curso aprenderas los fundamentos matematicos y programaras tus propios algoritmos geneticos desde cero.','Avanzado',30,'assets/images/courses/genetic-thumb.jpg','assets/images/courses/genetic-banner.jpg','Programacion intermedia (Python recomendado).|Matematicas basicas.|Estadistica elemental.','Entender los principios de la seleccion natural aplicados a la computacion.|Implementar operadores geneticos: seleccion, cruce y mutacion.|Definir funciones de aptitud correctamente.|Aplicar AG a problemas de optimizacion reales.','Inteligencia Artificial','Algoritmos Geneticos, IA, Optimizacion, Computacion Evolutiva','active',10),

('data-science','Data Science: Analisis y Visualizacion de Datos','Transforma datos en insights accionables con Python, pandas y visualizaciones profesionales.','Los datos son el nuevo petroleo. En este curso aprenderas el flujo completo del Data Science: desde la recoleccion y limpieza de datos hasta el analisis exploratorio y la visualizacion de insights que generen valor para las organizaciones. Usaras las herramientas estandar de la industria: Python, pandas, NumPy, matplotlib, seaborn y Jupyter Notebooks.','Intermedio',45,'assets/images/courses/ds-thumb.jpg','assets/images/courses/ds-banner.jpg','Python basico.|Estadistica descriptiva.|Excel o Google Sheets (recomendado).','Recolectar y limpiar datasets reales.|Realizar analisis exploratorio de datos (EDA).|Crear visualizaciones profesionales e interactivas.|Identificar patrones y tendencias en datos.|Comunicar hallazgos efectivamente.','Ciencia de Datos','Data Science, Python, pandas, visualizacion, EDA','active',12),

('javascript-moderno','JavaScript Moderno: ES6+ y mas alla','Domina JavaScript moderno desde los fundamentos hasta async/await y primeros pasos con React.','JavaScript es el lenguaje del web. En este curso aprenderas JavaScript desde sus fundamentos hasta las caracteristicas modernas de ES6+: arrow functions, destructuring, Promises, async/await, modulos y mucho mas. Luego de dominar el lenguaje, daras tus primeros pasos con React para el frontend, convirtiendote en un desarrollador JavaScript moderno y demandado.','Intermedio',55,'assets/images/courses/js-thumb.jpg','assets/images/courses/js-banner.jpg','HTML y CSS basico.|Logica de programacion elemental.','Dominar JavaScript ES6+ completamente.|Trabajar con arrays, objetos y funciones de orden superior.|Manejar asincronismo con Promises y async/await.|Crear componentes con React.|Gestionar el estado de aplicaciones.|Construir proyectos reales para el portafolio.','Desarrollo Web','JavaScript, ES6, React, Frontend','active',14);

